+func ownerKindForObject(obj client.Object) string {
+	switch obj.(type) {
+	case *appsv1.Deployment:
+		return "Deployment"
+	case *appsv1.StatefulSet:
+		return "StatefulSet"
+	case *argov1alpha1.Rollout:
+		return rollouts.RolloutKind
+	default:
+		return ""
+	}
